// Compute month range (current month)
const now = new Date();
const firstOfMonth = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth(), 1));
const lastOfMonth = new Date(Date.UTC(now.getUTCFullYear(), now.getUTCMonth() + 1, 0));

const monthStart = firstOfMonth.toISOString().slice(0, 10);
const monthEnd = lastOfMonth.toISOString().slice(0, 10);

// Also compute 90-day lookback for signals
const lookback = new Date(now);
lookback.setUTCDate(lookback.getUTCDate() - 90);
const lookbackDate = lookback.toISOString().slice(0, 10);

return [{ json: { month_start: monthStart, month_end: monthEnd, lookback_date: lookbackDate } }];

// Build structured context for LLM synthesis
const monthRange = $('Compute Month Range').first().json;
const signals = $('Load Signals (90 days)').all().map(i => i.json);

// Parse objection library
let objections = [];
try {
  const objLib = $('Load Objection Library').first().json;
  const contentJson = typeof objLib.content_json === 'string' ? JSON.parse(objLib.content_json) : objLib.content_json;
  objections = contentJson?.objections || [];
} catch (e) { /* no objection data yet */ }

// Parse swipe file
let swipePhrases = [];
try {
  const swipeData = $('Load Swipe File').first().json;
  const contentJson = typeof swipeData.content_json === 'string' ? JSON.parse(swipeData.content_json) : swipeData.content_json;
  swipePhrases = contentJson?.phrases || [];
} catch (e) { /* no swipe data yet */ }

// Parse battlecards
let competitors = [];
try {
  competitors = $('Load Battlecards').all().map(i => {
    const cj = typeof i.json.content_json === 'string' ? JSON.parse(i.json.content_json) : i.json.content_json;
    return {
      competitor_name: i.json.competitor_name,
      what_changed: cj?.what_changed_this_week || [],
      talk_tracks: cj?.talk_tracks || [],
      win_themes: cj?.win_themes || [],
      lose_themes: cj?.lose_themes || []
    };
  });
} catch (e) { /* no battlecard data yet */ }

// Group signals by type for dimension analysis
const signalsByType = {};
for (const s of signals) {
  signalsByType[s.signal_type] = signalsByType[s.signal_type] || [];
  signalsByType[s.signal_type].push({
    title: s.title,
    summary: (s.summary || '').substring(0, 200),
    severity: s.severity,
    signal_type: s.signal_type
  });
}

// Top objections (max 20)
const topObjections = objections.slice(0, 20).map(o => ({
  text: o.objection_text,
  category: o.category,
  frequency: o.frequency,
  personas: o.personas
}));

// Top swipe phrases (max 25)
const topPhrases = swipePhrases.slice(0, 25).map(p => ({
  phrase: p.phrase,
  category: p.category,
  persona: p.persona,
  trend: p.trend
}));

// Competitor names
const competitorNames = competitors.map(c => c.competitor_name);

// Build Anthropic API body
const systemPrompt = `You are a strategic GTM analyst building a Maturity Model — a 4-stage capability progression that helps buyers self-identify their current stage without naming competitors.

OUTPUT: Strict JSON only. No markdown, no explanations outside JSON.

SCHEMA:
{
  "title": "string (e.g. 'The Competitive Intelligence Maturity Model')",
  "dimensions": [
    {
      "id": "string (snake_case identifier)",
      "label": "string (human-readable dimension name)",
      "stages": [
        {
          "stage_number": 1,
          "name": "string (e.g. 'Ad Hoc')",
          "description": "string (what this stage looks like)",
          "what_works": "string (strengths at this level)",
          "what_breaks": "string (limitations that trigger need to level up)",
          "trigger_to_next": "string (specific event that moves org to next stage)",
          "discovery_questions": ["string (3-5 diagnostic questions)"],
          "talk_track": "string (how to talk about this stage with buyers)",
          "objection_reframes": [
            {
              "original_objection": "string (from objection library data)",
              "readiness_reframe": "string (reframe as stage-based insight)"
            }
          ],
          "swipe_phrases": ["string (buyer language typical at this stage)"]
        }
      ]
    }
  ],
  "competitor_mapping": [
    {
      "competitor_name": "string",
      "dimension_id": "string",
      "stage_number": 1|2|3|4,
      "evidence_summary": "string (based on signals and battlecard data)",
      "confidence": "low|medium|high"
    }
  ],
  "generation_metadata": {
    "signal_count": number,
    "objection_count": number,
    "swipe_phrase_count": number
  }
}

RULES:
1. Generate 2-4 capability dimensions based on what the signal data reveals about how the market segments
2. Each dimension MUST have exactly 4 stages numbered 1-4
3. Stage 4 is always the most advanced — where the user's product implicitly positions
4. Stage naming should be progressive and aspirational:
   - GOOD: "Ad Hoc → Functional → Systematic → Predictive"
   - BAD: "No Tool → Basic Tool → Good Tool → Best Tool"
5. NEVER name competitors in buyer-facing fields (stages, talk_tracks, discovery_questions, objection_reframes, swipe_phrases)
6. competitor_mapping is internal only — populate for each competitor across each dimension
7. Discovery questions must help sellers identify buyer's current stage through open-ended conversation
8. Talk tracks should NOT attack — they should acknowledge the current stage and describe the next level
9. Objection reframes must connect the original objection to a stage-specific readiness insight
10. Swipe phrases should reflect real buyer language from the data
11. If insufficient data for a dimension, omit it rather than hallucinate
12. competitor_mapping confidence: "high" = strong signal evidence, "medium" = inferred from positioning, "low" = limited data`;

const userContent = \`Build a maturity model from this market data:

SIGNAL SUMMARY (last 90 days, \${signals.length} total):
\${JSON.stringify(signalsByType, null, 2)}

OBJECTIONS (\${topObjections.length} entries):
\${JSON.stringify(topObjections, null, 2)}

BUYER LANGUAGE / SWIPE PHRASES (\${topPhrases.length} entries):
\${JSON.stringify(topPhrases, null, 2)}

COMPETITORS (for internal mapping):
\${JSON.stringify(competitorNames)}

COMPETITOR CONTEXT:
\${JSON.stringify(competitors.map(c => ({ name: c.competitor_name, win_themes: c.win_themes, lose_themes: c.lose_themes })), null, 2)}

Generate a maturity model with 2-4 dimensions, 4 stages each, with talk tracks, discovery questions, objection reframes, and competitor mapping.\`;

const anthropicBody = {
  model: 'claude-sonnet-4-20250514',
  max_tokens: 6000,
  temperature: 0.3,
  system: systemPrompt,
  messages: [{ role: 'user', content: userContent }]
};

return [{
  json: {
    month_start: monthRange.month_start,
    month_end: monthRange.month_end,
    signal_count: signals.length,
    objection_count: topObjections.length,
    swipe_phrase_count: topPhrases.length,
    signal_ids: signals.map(s => s.id),
    anthropic_body: anthropicBody
  }
}];

// Parse Anthropic response and generate markdown
const context = $('Build LLM Context').first().json;
const response = $input.first().json;

// Extract text content from Anthropic response
let rawText = '';
if (response.content && response.content[0]) {
  rawText = response.content[0].text || '';
}

// Parse JSON (handle potential markdown code fences)
let content;
try {
  const cleaned = rawText.replace(/```json\n?/g, '').replace(/```\n?/g, '').trim();
  content = JSON.parse(cleaned);
} catch (e) {
  throw new Error('Failed to parse LLM response as JSON: ' + e.message + '\n\nRaw: ' + rawText.substring(0, 500));
}

// Validate required fields
if (!content.dimensions || !Array.isArray(content.dimensions)) {
  throw new Error('Missing or invalid dimensions array in LLM response');
}

// Ensure generation_metadata
content.generation_metadata = {
  signal_count: context.signal_count || 0,
  objection_count: context.objection_count || 0,
  swipe_phrase_count: context.swipe_phrase_count || 0
};

// Generate markdown export
let md = `# ${content.title || 'Maturity Model'}\n\n`;
md += `*Generated: ${new Date().toISOString().slice(0, 10)}*\n\n`;

for (const dim of content.dimensions) {
  md += `## ${dim.label}\n\n`;
  for (const stage of dim.stages) {
    md += `### Stage ${stage.stage_number}: ${stage.name}\n\n`;
    md += `${stage.description}\n\n`;
    md += `**What Works:** ${stage.what_works}\n\n`;
    md += `**What Breaks:** ${stage.what_breaks}\n\n`;
    md += `**Trigger to Next Stage:** ${stage.trigger_to_next}\n\n`;

    if (stage.discovery_questions && stage.discovery_questions.length > 0) {
      md += `**Discovery Questions:**\n`;
      stage.discovery_questions.forEach(q => { md += `- ${q}\n`; });
      md += `\n`;
    }

    md += `**Talk Track:**\n> ${stage.talk_track}\n\n`;

    if (stage.objection_reframes && stage.objection_reframes.length > 0) {
      md += `**Objection Reframes:**\n`;
      stage.objection_reframes.forEach(r => {
        md += `- "${r.original_objection}" → ${r.readiness_reframe}\n`;
      });
      md += `\n`;
    }

    if (stage.swipe_phrases && stage.swipe_phrases.length > 0) {
      md += `**Buyer Language:** ${stage.swipe_phrases.map(p => `"${p}"`).join(', ')}\n\n`;
    }

    md += `---\n\n`;
  }
}

return [{
  json: {
    month_start: context.month_start,
    month_end: context.month_end,
    content: content,
    markdown: md,
    signal_ids: context.signal_ids || [],
    dimension_count: content.dimensions.length
  }
}];

// Extract competitor positions for batch upsert
const modelId = $('Upsert Maturity Model').first().json.id;
const content = $('Parse Response + Generate MD').first().json.content;
const positions = content.competitor_mapping || [];

if (positions.length === 0) {
  return [{ json: { skip: true, message: 'No competitor positions to upsert' } }];
}

// Build batch SQL
const values = positions.map(p => {
  const evidenceSafe = JSON.stringify({ summary: (p.evidence_summary || '').replace(/'/g, "''") });
  return `('${modelId}', '${p.dimension_id}', '${(p.competitor_name || '').replace(/'/g, "''")}', ${p.stage_number}, '${evidenceSafe}'::jsonb, '${p.confidence || 'medium'}')`;
}).join(',\n');

const sql = `INSERT INTO gtm_artifacts.maturity_model_competitor_positions
  (maturity_model_id, dimension_id, competitor_name, stage_number, evidence, confidence)
VALUES
${values}
ON CONFLICT (maturity_model_id, dimension_id, competitor_name) DO UPDATE SET
  stage_number = EXCLUDED.stage_number,
  evidence = EXCLUDED.evidence,
  confidence = EXCLUDED.confidence,
  previous_stage = maturity_model_competitor_positions.stage_number,
  moved_at = CASE 
    WHEN maturity_model_competitor_positions.stage_number != EXCLUDED.stage_number 
    THEN now() 
    ELSE maturity_model_competitor_positions.moved_at 
  END;`;

return [{ json: { sql: sql, position_count: positions.length } }];
